<template>
  <div class="resume-login-page min-h-screen bg-slate-50 text-slate-800">
    <header class="gradient-hero flowing-gradient-cosmic hero-header">
      <div class="hero-inner">
        <span class="hero-eyebrow">DUT BLOCKCHAIN RECRUITMENT</span>
        <h1 class="hero-title">简历投递 · 登录</h1>
        <p class="hero-subtitle">
          请务必填写正确的姓名与学号，并注意下载的credential.json。
        </p>
      </div>
    </header>

    <main class="mx-auto max-w-6xl px-4 py-10 sm:px-6 lg:px-8">
      <section class="grid gap-8 lg:grid-cols-[1fr_320px]">
        <article class="rounded-2xl border border-slate-200 bg-white p-6 shadow-[0_12px_36px_rgba(15,23,42,0.08)] sm:p-8">
          <form class="space-y-6" @submit.prevent="handleGenerate">
            <div class="grid gap-4 sm:grid-cols-2">
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">姓名 *</label>
                <input
                  v-model.trim="form.username"
                  type="text"
                  required
                  class="field-input"
                  placeholder="请输入真实姓名"
                >
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">学号 *</label>
                <input
                  v-model.trim="form.studentId"
                  type="text"
                  required
                  class="field-input"
                  placeholder="请输入学号"
                >
              </div>
            </div>

            <p v-if="errorMessage" class="rounded-lg border border-red-300 bg-red-50 px-3 py-2 text-sm text-red-700">
              {{ errorMessage }}
            </p>

            <p v-if="successMessage" class="rounded-lg border border-emerald-300 bg-emerald-50 px-3 py-2 text-sm text-emerald-700">
              {{ successMessage }}
            </p>

            <div class="action-row">
              <button type="submit" class="action-btn action-btn-primary" :disabled="isGenerating">
                {{ isGenerating ? '生成中...' : '生成密钥对并下载凭证' }}
              </button>
              <button
                v-if="hasCredential"
                type="button"
                class="action-btn action-btn-ghost"
                @click="goVerify"
              >
                前往校验与提交
              </button>
            </div>
          </form>
        </article>

        <aside class="space-y-6">
          <section class="rounded-2xl border border-slate-200 bg-white p-6 shadow-[0_10px_28px_rgba(15,23,42,0.06)]">
            <h2 class="text-lg font-semibold text-slate-900">流程说明</h2>
            <ol class="mt-4 space-y-2 text-sm leading-6 text-slate-600 list-decimal pl-4">
              <li>当前页登录并生成密钥，下载 credential.json。</li>
              <li>进入校验页上传 credential.json，执行 challenge-response 验证。</li>
              <li>验证通过后填写报名信息，完成最终提交。</li>
              <li>注意！如果无法登录请及时联系唐明迪组长~</li>
            </ol>
          </section>
        </aside>
      </section>
    </main>
  </div>
</template>

<script setup lang="ts">
import axios from 'axios'
import { computed, reactive, ref } from 'vue'
import { useRouter } from 'vue-router'
import { registerCredential } from '@/api/zkpAuth'
import { bnToHex, generateKeyPair } from '@/utils/zkp'

interface LoginForm {
  username: string
  studentId: string
}

interface CredentialFile extends LoginForm {
  x: string
  createdAt: number
}

const router = useRouter()

const form = reactive<LoginForm>({
  username: '',
  studentId: ''
})

const isGenerating = ref(false)
const errorMessage = ref('')
const successMessage = ref('')
const credential = ref<CredentialFile | null>(null)

const hasCredential = computed(() => Boolean(credential.value?.x))

const resolveErrorMessage = (error: unknown, fallback: string) => {
  if (!axios.isAxiosError(error)) {
    return error instanceof Error ? error.message : fallback
  }

  if (!error.response) {
    if (typeof navigator !== 'undefined' && navigator.onLine === false) {
      return '当前网络已断开，请连接网络后重试。'
    }
    return '无法连接到认证服务，请稍后重试。'
  }

  const status = error.response.status
  const responseData = error.response.data as
    | string
    | {
      message?: string
      msg?: string
      error?: string | { message?: string; msg?: string }
      data?: { message?: string; msg?: string }
    }
    | undefined

  const backendMessage = (() => {
    if (typeof responseData === 'string') {
      return responseData
    }
    if (!responseData || typeof responseData !== 'object') {
      return ''
    }

    if (typeof responseData.message === 'string') return responseData.message
    if (typeof responseData.msg === 'string') return responseData.msg
    if (typeof responseData.error === 'string') return responseData.error

    if (responseData.error && typeof responseData.error === 'object') {
      if (typeof responseData.error.message === 'string') return responseData.error.message
      if (typeof responseData.error.msg === 'string') return responseData.error.msg
    }

    if (responseData.data && typeof responseData.data === 'object') {
      if (typeof responseData.data.message === 'string') return responseData.data.message
      if (typeof responseData.data.msg === 'string') return responseData.data.msg
    }

    return ''
  })()

  if (backendMessage && backendMessage.trim()) {
    return backendMessage.trim()
  }

  if (status === 400) {
    return '提交信息有误，请检查姓名和学号后重试。'
  }

  if (status === 409) {
    return '该学号已完成注册，请直接前往校验页面。'
  }

  if (status >= 500) {
    return '服务暂时不可用，请稍后再试。'
  }

  return fallback
}

const downloadCredential = (payload: CredentialFile) => {
  const blob = new Blob([JSON.stringify(payload)], { type: 'application/json' })
  const url = URL.createObjectURL(blob)
  const anchor = document.createElement('a')
  anchor.href = url
  anchor.download = 'credential.json'
  anchor.click()
  URL.revokeObjectURL(url)
}

const handleGenerate = async () => {
  errorMessage.value = ''
  successMessage.value = ''

  if (!form.username || !form.studentId) {
    errorMessage.value = '请输入姓名和学号后再继续。'
    return
  }

  isGenerating.value = true
  try {
    const { x, y } = generateKeyPair()
    await registerCredential({
      username: form.username,
      studentId: form.studentId,
      publicKeyY: bnToHex(y)
    })

    credential.value = {
      username: form.username,
      studentId: form.studentId,
      x: bnToHex(x),
      createdAt: Date.now()
    }

    downloadCredential(credential.value)
    successMessage.value = '密钥已生成并下载，请妥善保管 credential.json。'
  } catch (error: unknown) {
    errorMessage.value = resolveErrorMessage(error, '登录失败，请稍后重试。')
  } finally {
    isGenerating.value = false
  }
}

const goVerify = () => {
  router.push('/resume-verify')
}
</script>

<style scoped>
.field-input {
  width: 100%;
  border-radius: 0.75rem;
  border: 1px solid rgb(203, 213, 225);
  background: rgb(255, 255, 255);
  padding: 0.72rem 0.95rem;
  color: rgb(15, 23, 42);
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.field-input::placeholder {
  color: rgb(148, 163, 184);
}

.field-input:focus {
  border-color: rgb(59, 130, 246);
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.14);
}

.action-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
}

.action-btn {
  border: none;
  border-radius: 0.75rem;
  padding: 0.72rem 1rem;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s ease;
}

.action-btn:disabled {
  opacity: 0.65;
  cursor: not-allowed;
}

.action-btn-primary {
  color: #fff;
  background: linear-gradient(135deg, #0f172a, #1e40af);
}

.action-btn-primary:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 10px 20px rgba(30, 64, 175, 0.22);
}

.action-btn-ghost {
  color: #1e3a8a;
  background: #e2e8f0;
}

.action-btn-ghost:hover {
  background: #cbd5e1;
}
</style>
